function TaskDialog()
this:AddTalk("<p><n color=\"255,255,255,0\">(GetName)</n><n></n><n color=\"255,0,255,255\"> 你好！</n></p>");
this:AddTalk("<p><n color=\"255,0,255,0\">欢迎来到全新抽奖玩法，抽奖可获得游戏内不少物品！还有几率得稀有道具！</n></p>");
this:AddTalk("<p><n color=\"255,0,255,255\">抽奖额外奖励：</n></p>");
this:AddTalk("<p><n color=\"255,255,255,0\">达到</n><n></n><n color=\"255,255,255,255\">50 </n><n></n><n color=\"255,0,255,255\">150 </n><n></n><n color=\"255,255,255,0\">300 </n><n></n><n color=\"255,0,255,0\">500 </n><n></n><n color=\"255,255,0,255\">1000 </n><n></n><n color=\"255,255,255,0\">次可领取额外丰厚奖励！</n></p>");
this:AddTalk("<p><n color=\"255,0,255,0\">抽奖土豪奖励：</n></p>")
this:AddTalk("<p><n color=\"255,255,0,0\">抽奖达1000次奖励绝世坐骑！</n></p>")
this:AddTaskCmdItem("[一连抽]金子抽奖：100锭金子/次(0)", "v610001", 1000, 1)
this:AddCloseItem("------------------------------(0)")
this:AddTaskCmdItem("[十连抽]金子抽奖：1000锭金子/次(0)", "v610001", 1000, 11)
this:AddCloseItem("------------------------------(0)")
this:AddTaskCmdItem("[累计奖]抽奖50次奖励-没达到(0)", "v5134", 1010, 99)
this:AddCloseItem("离开")
end

